9437     std::swap(R0, R1);
9438     RPred = ICmpInst::getSwappedCmpPredicate(RPred);
9439   }
9440   if (R0 == L1) {
9441     std::swap(L0, L1);
9442     LPred = ICmpInst::getSwappedCmpPredicate(LPred);
9443   }
9444   if (L1 == R1) {
9445     // If we have L0 == R0 and L1 == R1, then make L1/R1 the constants.
9446     if (L0 != R0 || match(L0, m_ImmConstant())) {
9447       std::swap(L0, L1);
9448       LPred = ICmpInst::getSwappedCmpPredicate(LPred);
9449       std::swap(R0, R1);
9450       RPred = ICmpInst::getSwappedCmpPredicate(RPred);
9451     }
9452   }
9453 
9454   // See if we can infer anything if operand-0 matches and we have at least one
9455   // constant.
