258   case CmpInst::ICMP_ULE:
259     return getUnsignedMax().ule(Other.getUnsignedMin());
260   case CmpInst::ICMP_UGT:
261     return getUnsignedMin().ugt(Other.getUnsignedMax());
262   case CmpInst::ICMP_UGE:
